mapper.select:
select dbo.getCommonName('area', c.area_cd) as areaCd ,b.po_no ,a.proc_order_date ,b.make_No ,b.lot_no ,a.item_cd ,d.item_name ,a.order_qty ,dbo.getCommonName('PROC_STATUS', a.proc_status) as proc_status ,dbo.getCommonName('batch_STATUS', b.batch_status) as batch_status ,a.proc_cd ,c.work_order_id ,b.work_batch_id ,a.work_proc_id ,c.client_id ,e.client_name from TB_WORK_ORDER_PROC a inner join TB_WORK_ORDER_BATCH b on b.work_batch_id = a.work_batch_id inner join TB_WORK_ORDER_MST c on b.work_order_id = c.work_order_id inner join tb_item_mst d on d.item_cd = a.item_cd left outer join tb_client_mst e on e.client_id = c.client_id where a.proc_cd = 'PRC002'
AND c.area_cd = #{areaCd}
and a.item_cd = #{itemCd}
and d.item_name LIKE '%' + #{itemName} + '%'
and e.client_name LIKE '%' + #{clientName} + '%'
and a.proc_status = #{procStatus}
ORDER BY c.work_order_date DESC, c.seq DESC

mapper.update:
update TB_WORK_ORDER_PROC
set    proc_status          = #{procStatus}
      ,storage_cd           = #{storageCd}
      ,work_equipment_Cd    = #{workEquipmentCd}
      ,prod_date            = convert(date, getdate(), -23)
      ,work_start_time      = getDate()
      ,etc                  = #{etc}
      ,test_no              = #{testNo}
      ,upd_id               = #{userId}
      ,upd_dt               = getDate()
where  work_proc_id         = #{workProcId}

update tb_weigh_info
set     make_yn         =#{makeYn}
      , make_time        =#{makeTime}
      , maker           =#{maker}
      , make_confirmer  =#{makeConfirmer}
      , make_Qty        =#{makeQty}
      , upd_id          =#{userId}
      , upd_dt          = getDate()
where  weigh_id         = #{weighId}
